// EMERGENCY STOP CHECK
// Must be the first code node in every workflow, right after the trigger.
// Checks the EMERGENCY_STOP environment variable. If true, sends a
// notification to Discord and halts the workflow (returns empty array).
//
// Referenced in: crisis.md, n8n-workflow-specs.md
// Variable: EMERGENCY_STOP (Settings > Variables)

const emergencyStop = $env.EMERGENCY_STOP;

if (emergencyStop === 'true' || emergencyStop === true) {
  const workflowName = $workflow.name || 'Unknown Workflow';
  const timestamp = new Date().toISOString();

  const discordUrl = $env.DISCORD_WEBHOOK_URL;
  if (discordUrl) {
    try {
      await fetch(discordUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          content: `**EMERGENCY STOP ACTIVE** | Workflow "${workflowName}" halted at ${timestamp}. No content was published. Set EMERGENCY_STOP=false in n8n variables to resume.`
        })
      });
    } catch (e) {
      // Discord notification failed, but we still halt.
    }
  }

  return [];
}

return $input.all();

// PRE-POST EMERGENCY STOP CHECK
// Second check right before writing drafts and sending Discord notifications.
// Catches mid-execution activation of EMERGENCY_STOP.

const emergencyStop = $env.EMERGENCY_STOP;

if (emergencyStop === 'true' || emergencyStop === true) {
  return [];
}

return $input.all();

const taostats = $('Taostats 7d History').first().json;
const taoPrices = $('CoinGecko TAO 7d').first().json;
const alphaPrices = $('CoinGecko SN106 7d').first().json;
const bridge = $('Bridge Volume 7d').first().json;
const repos = $('GitHub Repos').first().json;

let taoWeeklyChange = 'N/A';
if (taoPrices?.prices?.length >= 2) {
  const start = taoPrices.prices[0][1];
  const end = taoPrices.prices[taoPrices.prices.length - 1][1];
  taoWeeklyChange = ((end - start) / start * 100).toFixed(1);
}

let alphaWeeklyChange = 'N/A';
if (alphaPrices?.prices?.length >= 2) {
  const start = alphaPrices.prices[0][1];
  const end = alphaPrices.prices[alphaPrices.prices.length - 1][1];
  alphaWeeklyChange = ((end - start) / start * 100).toFixed(1);
}

let activeRepos = 'N/A';
if (Array.isArray(repos)) {
  const oneWeekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
  activeRepos = repos.filter(r => r.pushed_at > oneWeekAgo && !r.fork).length;
}

const weekData = {
  tao_current_price: taoPrices?.prices?.length ? taoPrices.prices[taoPrices.prices.length - 1][1] : 'N/A',
  tao_weekly_change_pct: taoWeeklyChange,
  alpha_current_price: alphaPrices?.prices?.length ? alphaPrices.prices[alphaPrices.prices.length - 1][1] : 'N/A',
  alpha_weekly_change_pct: alphaWeeklyChange,
  bridge_total_tao: bridge?.total_tao_bridged ?? 'N/A',
  bridge_tx_count: bridge?.transaction_count ?? 'N/A',
  bridge_unique_wallets: bridge?.unique_wallets ?? 'N/A',
  bridge_chains: bridge?.chains ?? {},
  github_active_repos: activeRepos,
  sn106_pool_data: taostats ?? {},
  week_ending: new Date().toLocaleDateString('en-US', {
    year: 'numeric', month: 'long', day: 'numeric',
    timeZone: 'America/New_York'
  })
};

return [{ json: weekData }];

// DRY_RUN log: prepare data summary for Discord notification
const data = $input.first().json;

const summary = [
  `TAO: $${data.tao_current_price} (${data.tao_weekly_change_pct}% weekly)`,
  `Alpha: $${data.alpha_current_price} (${data.alpha_weekly_change_pct}% weekly)`,
  `Bridge: ${data.bridge_total_tao} TAO bridged`,
  `GitHub: ${data.github_active_repos} active repos`,
].join('\n');

return [{ json: { status: 'dry_run', summary, week_ending: data.week_ending, raw_data: data } }];

