// Write data summary to static data for later content generation.
// No Claude API call. Content generation happens manually via /generate-thread.
const data = $input.first().json;
const date = new Date().toISOString().split('T')[0];
const collectedAt = new Date().toISOString();

const dataSummary = {
  type: 'weekly-recap-data',
  status: 'pending_content_generation',
  collected_at: collectedAt,
  data: data,
  content_brief: 'Generate a weekly recap thread from this data using /generate-thread'
};

// Store in static data for retrieval
const staticData = $getWorkflowStaticData('global');
if (!staticData.drafts) {
  staticData.drafts = {};
}
staticData.drafts[`weekly-recap-${date}`] = dataSummary;

// Clean up old entries (keep last 4 weeks)
const draftKeys = Object.keys(staticData.drafts).sort();
if (draftKeys.length > 4) {
  for (const oldKey of draftKeys.slice(0, draftKeys.length - 4)) {
    delete staticData.drafts[oldKey];
  }
}

// Build a human-readable metrics preview for Discord
const metricsPreview = [
  `TAO: $${data.tao_current_price} (${data.tao_weekly_change_pct}% weekly)`,
  `Alpha: $${data.alpha_current_price} (${data.alpha_weekly_change_pct}% weekly)`,
  `Bridge: ${data.bridge_total_tao} TAO bridged, ${data.bridge_tx_count} txns, ${data.bridge_unique_wallets} wallets`,
  `GitHub: ${data.github_active_repos} active repos`
].join('\n');

return [{
  json: {
    status: 'data_collected',
    draft_key: `weekly-recap-${date}`,
    week_ending: data.week_ending,
    metrics_preview: metricsPreview
  }
}];

